        {"name": "Timothée Chalamet", "photo": "https://i.pinimg.com/1200x/62/77/94/627794dfcade124e102afc424a76b4e4.jpg", "bio": "American actor"},
        {"name": "Adrien Brody", "photo": "https://i.pinimg.com/736x/3b/73/0d/3b730da0d15b4fdbbf0731c87bd01209.jpg", "bio": "American actor and producer"},
        {"name": "Finn Wolfhard", "photo": "https://i.pinimg.com/1200x/a0/f1/de/a0f1de01e176c4466d8be875c52b667b.jpg", "bio": "Canadian actor producer, singer"},
        {"name": "Renata Raisvne", "photo": "https://encrypted-tbn0.gstatic.com/images?q=tbn:ANd9GcR1JYMCW2Rbyp9XFJT4vhr6eqceySPmFA2egXQTyQwGujI_yTLaKtmKnt1rSehhB1kDz0wiGaEpPTvNchsIeVj1EwTd-IH_Ikh2EX6auKOJAg&s=10", "bio": "Norwegian actress"},
