        {"name": "Johnny Depp", "photo": "https://www.film.ru/sites/default/files/styles/thumb_260x320/public/people/1456176-915122.jpg", "bio": "American actor and film director"},
        {"name": "Heath Ledger", "photo": "https://encrypted-tbn0.gstatic.com/images?q=tbn:ANd9GcQ8Ehiz6T8iF44VykjoRJGTswsnxxh5WlQlOn-bUMxLoGd09aXygSHI15wRRLFt0Md-LIER6xG7riZ64X_WnY7OWKG5aCSlzfLxP9sa6heu&s=10", "bio": "Australian actor and music video director"},
